import type { Metadata } from "next";
import ProjectPage from "@/components/projects/ProjectPage";
import { JsonLd, articleSchema } from "@/components/seo/JsonLd";
import identity from "@/content/about/identity";
import { projects } from "@/content/projects";
import { getProjectMetadata } from "@/lib/projects/loader";
import type { ProjectMetadata } from "@/lib/projects/types";

const SITE_URL =
  process.env.NEXT_PUBLIC_SITE_URL ??
  process.env.SITE_URL ??
  "https://personalwebsite-beta-nine.vercel.app";

// Build a 110-155 char description from the project's tagline + first
// sentence of its framing. Long taglines+framings get truncated at the
// nearest word boundary.
function buildDescription(meta: ProjectMetadata): string {
  const firstSentence = meta.framing.match(/^[^.!?]+[.!?]/)?.[0] ?? meta.framing;
  const candidate = `${meta.tagline} ${firstSentence}`.replace(/\s+/g, " ").trim();
  if (candidate.length <= 155) return candidate;
  const slice = candidate.slice(0, 152);
  const lastSpace = slice.lastIndexOf(" ");
  return `${slice.slice(0, lastSpace > 0 ? lastSpace : 152)}…`;
}

export function generateStaticParams() {
  return projects.map((p) => ({ slug: p.slug }));
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ slug: string }>;
}): Promise<Metadata> {
  const { slug } = await params;
  const meta = await getProjectMetadata(slug);
  if (!meta) return {};
  const description = buildDescription(meta);
  const path = `/projects/${slug}`;
  const title = `${meta.title} — ${meta.tagline}`;
  return {
    title,
    description,
    alternates: { canonical: path },
    openGraph: {
      type: "article",
      url: path,
      title,
      description,
    },
    twitter: {
      card: "summary_large_image",
      title,
      description,
    },
    robots: { index: true, follow: true },
  };
}

export default async function Page({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const meta = await getProjectMetadata(slug);
  const ld = meta
    ? articleSchema({
        url: `${SITE_URL}/projects/${slug}`,
        headline: `${meta.title} — ${meta.tagline}`,
        description: buildDescription(meta),
        authorName: identity.fullName,
        authorUrl: SITE_URL,
        about: meta.title,
      })
    : null;
  return (
    <>
      {ld ? <JsonLd data={ld} /> : null}
      <ProjectPage slug={slug} />
    </>
  );
}

// Single source of truth for who Michael is, used by the shell, the
// about page, the LLM persona, and the landing hero. The new fields
// (fullName, tagline, summary, email, location, currentRole) were
// introduced in suite 20/P02 for v2 voice; the legacy fields
// (name, roles, based, channels) remain so existing consumers do not
// have to change in the same change set.
const fullName = "Michael Quintin";
const email = "michael@hivemind.ai";
const location = "North America";
const currentRole = "Founder of Hivemind";
const roles = [currentRole, "Author", "Researcher"];

const channels = [
  { label: "email", href: `mailto:${email}` },
  { label: "LinkedIn", href: "https://www.linkedin.com/in/michael-quintin-5555b4283/" },
  { label: "X", href: "https://x.com/quintinpublic" },
  { label: "GitHub", href: "https://github.com/mrquintin" },
];

const identity = {
  fullName,
  name: fullName,
  tagline: "Founder and writer building tools for clear thinking under uncertainty.",
  summary:
    "Michael Quintin is the founder of Hivemind and the author of Purposeless Efficiency. He builds software and writing for operators who reason carefully under uncertainty.",
  email,
  location,
  based: location,
  currentRole,
  roles,
  channels,
};

export default identity;

